mapper.insert:
INSERT INTO relics
relic_code, site_id, site_name, name, type, position_within_site, excavation_area, excavation_unit, era, stratigraphy, structure_description, dimensions, orientation, burial_depth, preservation_status, function_purpose, cultural_features, related_relics, images, drawings, notes, created_by, create_time, update_time
#{relicCode}'', #{siteId}, #{siteName}, #{name}, #{type}, #{positionWithinSite}, #{excavationArea}, #{excavationUnit}, #{era}, #{stratigraphy}, #{structureDescription}, #{dimensions}, #{orientation}, #{burialDepth}, #{preservationStatus}, #{functionPurpose}, #{culturalFeatures}, #{relatedRelics}, #{images}, #{drawings}, #{notes}, #{createdBy}, #{createTime}, #{updateTime}

mapper.select:
SELECT * FROM relics


        AND name LIKE CONCAT('%', #{name}, '%')


        AND relic_code = #{relicCode}


        AND site_name LIKE CONCAT('%', #{siteName}, '%')


        AND type = #{type}


ORDER BY create_time DESC

mapper.update:
UPDATE relics
relic_code = #{relicCode}, site_id = #{siteId}, site_name = #{siteName}, name = #{name}, type = #{type}, position_within_site = #{positionWithinSite}, excavation_area = #{excavationArea}, excavation_unit = #{excavationUnit}, era = #{era}, stratigraphy = #{stratigraphy}, structure_description = #{structureDescription}, dimensions = #{dimensions}, orientation = #{orientation}, burial_depth = #{burialDepth}, preservation_status = #{preservationStatus}, function_purpose = #{functionPurpose}, cultural_features = #{culturalFeatures}, related_relics = #{relatedRelics}, images = #{images}, drawings = #{drawings}, notes = #{notes}, update_time = #{updateTime}
WHERE id = #{id}
